import sys

def main():
    input = sys.stdin.read
    data = input().split()

    n = int(data[0])
    matrix = []
    index = 1

    for _ in range(n):
        row = list(map(int, data[index:index + n]))
        matrix.append(row)
        index += n

    for i in range(n):
        neighbors = []
        for j in range(n):
            if matrix[i][j] == 1:
                neighbors.append(j + 1)
        print(' '.join(map(str, neighbors)))

if __name__ == "__main__":
    main()
